166→// detectToolchains scans the home directory for common toolchain directories.
167→func detectToolchains() []string {
168→	home := os.Getenv("HOME")
169→	if home == "" {
170→		return nil
171→	}
172→
173→	candidates := []string{
174→		filepath.Join(home, ".cargo"),
175→		filepath.Join(home, ".rustup"),
176→		filepath.Join(home, "go", "pkg"),
177→		filepath.Join(home, ".npm"),
178→		filepath.Join(home, ".nvm"),
179→		filepath.Join(home, ".pyenv"),
180→		filepath.Join(home, ".gradle"),
181→		filepath.Join(home, ".m2"),
182→	}
183→
184→	// Also check for ~/.local/lib/python* directories
185→	pythonGlob := filepath.Join(home, ".local", "lib", "python*")
186→	if matches, err := filepath.Glob(pythonGlob); err == nil {
187→		candidates = append(candidates, matches...)
188→	}
189→
190→	var found []string
191→	for _, dir := range candidates {
192→		if info, err := os.Stat(dir); err == nil && info.IsDir() {
193→			found = append(found, dir)
194→		}
195→	}
196→	return found
197→}
