199→// detectEnvVars looks for .env files in the project and parses KEY=VALUE pairs.
200→func detectEnvVars(projectPath string) map[string]string {
201→	result := make(map[string]string)
202→
203→	// Prefer example files over actual .env (safer defaults)
204→	files := []struct {
205→		name        string
206→		usePlaceholder bool
207→	}{
208→		{".env.example", true},
209→		{".env.sample", true},
210→		{".env", false},
211→	}
212→
213→	for _, f := range files {
214→		path := filepath.Join(projectPath, f.name)
215→		vars, err := parseEnvFile(path)
216→		if err != nil {
217→			continue
218→		}
219→		if f.usePlaceholder {
220→			// For example files, use the value as-is (likely a placeholder)
221→			for k, v := range vars {
222→				if _, exists := result[k]; !exists {
223→					result[k] = v
224→				}
225→			}
226→		} else {
227→			fmt.Printf("  Note: .env contains actual values — review before sharing with agents.\n")
228→			for k, v := range vars {
229→				if _, exists := result[k]; !exists {
230→					result[k] = v
231→				}
232→			}
233→		}
234→	}
235→	return result
236→}
237→
238→// parseEnvFile reads a .env-style file and returns KEY=VALUE pairs.
239→func parseEnvFile(path string) (map[string]string, error) {
240→	f, err := os.Open(path)
241→	if err != nil {
242→		return nil, err
243→	}
244→	defer f.Close()
245→
246→	result := make(map[string]string)
247→	scanner := bufio.NewScanner(f)
248→	for scanner.Scan() {
249→		line := strings.TrimSpace(scanner.Text())
250→		if line == "" || strings.HasPrefix(line, "#") {
251→			continue
252→		}
253→		idx := strings.Index(line, "=")
254→		if idx < 1 {
255→			continue
256→		}
257→		key := strings.TrimSpace(line[:idx])
258→		value := strings.TrimSpace(line[idx+1:])
259→		// Strip surrounding quotes
260→		if len(value) >= 2 && ((value[0] == '"' && value[len(value)-1] == '"') || (value[0] == '\'' && value[len(value)-1] == '\'')) {
261→			value = value[1 : len(value)-1]
262→		}
263→		result[key] = value
264→	}
265→	return result, scanner.Err()
266→}
