376→// showSimpleDiff prints a basic line-by-line diff between two strings.
377→func showSimpleDiff(old, new string) {
378→	oldLines := strings.Split(old, "\n")
379→	newLines := strings.Split(new, "\n")
380→
381→	// Simple approach: show removed lines with -, added lines with +
382→	oldSet := make(map[string]int)
383→	for _, l := range oldLines {
384→		oldSet[l]++
385→	}
386→	newSet := make(map[string]int)
387→	for _, l := range newLines {
388→		newSet[l]++
389→	}
390→
391→	for _, l := range oldLines {
392→		if newSet[l] <= 0 {
393→			fmt.Printf("  - %s\n", l)
394→		} else {
395→			newSet[l]--
396→		}
397→	}
398→	for _, l := range newLines {
399→		if oldSet[l] <= 0 {
400→			fmt.Printf("  + %s\n", l)
401→		} else {
402→			oldSet[l]--
403→		}
404→	}
405→}
406→
407→// askYesNo prompts the user for a yes/no answer. defaultYes controls the default when Enter is pressed.
408→func askYesNo(prompt string, defaultYes bool) bool {
409→	hint := "[Y/n]"
410→	if !defaultYes {
411→		hint = "[y/N]"
412→	}
413→	fmt.Printf("%s %s ", prompt, hint)
414→
415→	scanner := bufio.NewScanner(os.Stdin)
416→	if !scanner.Scan() {
417→		return defaultYes
418→	}
419→	answer := strings.TrimSpace(strings.ToLower(scanner.Text()))
420→	if answer == "" {
421→		return defaultYes
422→	}
423→	return answer == "y" || answer == "yes"
424→}
