// Package settings manages Claude Code settings files (~/.claude/settings.json).
package settings

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
)

// RequiredPermissions are Bash allow-list entries that agentsea needs
// for teammate management (tmux pane spawning, monitoring, cleanup).
var RequiredPermissions = []string{
	"Bash(tmux capture-pane*)",
	"Bash(tmux has-session*)",
	"Bash(tmux kill-pane*)",
	"Bash(tmux kill-session*)",
	"Bash(tmux kill-window*)",
	"Bash(tmux list-panes*)",
	"Bash(tmux list-sessions*)",
	"Bash(tmux list-windows*)",
	"Bash(tmux new-session*)",
	"Bash(tmux new-window*)",
	"Bash(tmux select-pane*)",
	"Bash(tmux select-window*)",
	"Bash(tmux send-keys*)",
	"Bash(tmux split-window*)",
}

// RequiredEnv are env vars that must be set in Claude Code settings
// for agent teams to work.
var RequiredEnv = map[string]string{
	"CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS": "1",
}

// RequiredGlobalConfig are top-level keys that must be set in ~/.claude.json
// for agentsea's teammate interception to work.
var RequiredGlobalConfig = map[string]string{
	"teammateMode": "tmux",
}

// SettingsPath returns the path to ~/.claude/settings.json.
func SettingsPath() string {
	return filepath.Join(os.Getenv("HOME"), ".claude", "settings.json")
}

// GlobalConfigPath returns the path to ~/.claude.json.
func GlobalConfigPath() string {
	return filepath.Join(os.Getenv("HOME"), ".claude.json")
}

// EnsurePermissions reads ~/.claude/settings.json, adds any missing
// required permissions to the allow list, and writes back if changed.
// Returns the number of permissions added.
func EnsurePermissions() (int, error) {
	path := SettingsPath()

	data, err := os.ReadFile(path)
	if err != nil && !os.IsNotExist(err) {
		return 0, fmt.Errorf("reading %s: %w", path, err)
	}

	// Parse existing settings (or start with empty object)
	var settings map[string]interface{}
	if len(data) > 0 {
		if err := json.Unmarshal(data, &settings); err != nil {
			return 0, fmt.Errorf("parsing %s: %w", path, err)
		}
	}
	if settings == nil {
		settings = make(map[string]interface{})
	}

	// Navigate to permissions.allow, creating if needed
	perms, _ := settings["permissions"].(map[string]interface{})
	if perms == nil {
		perms = make(map[string]interface{})
		settings["permissions"] = perms
	}

	allowRaw, _ := perms["allow"].([]interface{})
	existing := make(map[string]bool, len(allowRaw))
	for _, v := range allowRaw {
		if s, ok := v.(string); ok {
			existing[s] = true
		}
	}

	added := 0
	for _, perm := range RequiredPermissions {
		if !existing[perm] {
			allowRaw = append(allowRaw, perm)
			added++
		}
	}

	if added == 0 {
		return 0, nil
	}

	perms["allow"] = allowRaw
	settings["permissions"] = perms

	out, err := json.MarshalIndent(settings, "", "  ")
	if err != nil {
		return 0, fmt.Errorf("marshaling settings: %w", err)
	}

	// Ensure directory exists
	if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
		return 0, fmt.Errorf("creating settings dir: %w", err)
	}

	if err := os.WriteFile(path, append(out, '\n'), 0644); err != nil {
		return 0, fmt.Errorf("writing %s: %w", path, err)
	}

	return added, nil
}

// EnsureEnv ensures required env vars are set in settings.json.
// Returns the number of env vars added.
func EnsureEnv() (int, error) {
	path := SettingsPath()

	data, err := os.ReadFile(path)
	if err != nil && !os.IsNotExist(err) {
		return 0, fmt.Errorf("reading %s: %w", path, err)
	}

	var settings map[string]interface{}
	if len(data) > 0 {
		if err := json.Unmarshal(data, &settings); err != nil {
			return 0, fmt.Errorf("parsing %s: %w", path, err)
		}
	}
	if settings == nil {
		settings = make(map[string]interface{})
	}

	envMap, _ := settings["env"].(map[string]interface{})
	if envMap == nil {
		envMap = make(map[string]interface{})
		settings["env"] = envMap
	}

	added := 0
	for k, v := range RequiredEnv {
		if existing, ok := envMap[k].(string); !ok || existing != v {
			envMap[k] = v
			added++
		}
	}

	if added == 0 {
		return 0, nil
	}

	out, err := json.MarshalIndent(settings, "", "  ")
	if err != nil {
		return 0, fmt.Errorf("marshaling settings: %w", err)
	}

	if err := os.WriteFile(path, append(out, '\n'), 0644); err != nil {
		return 0, fmt.Errorf("writing %s: %w", path, err)
	}

	return added, nil
}

// EnsureGlobalConfig ensures required keys are set in ~/.claude.json.
// Returns the number of keys added/changed.
func EnsureGlobalConfig() (int, error) {
	path := GlobalConfigPath()

	data, err := os.ReadFile(path)
	if err != nil && !os.IsNotExist(err) {
		return 0, fmt.Errorf("reading %s: %w", path, err)
	}

	var config map[string]interface{}
	if len(data) > 0 {
		if err := json.Unmarshal(data, &config); err != nil {
			return 0, fmt.Errorf("parsing %s: %w", path, err)
		}
	}
	if config == nil {
		config = make(map[string]interface{})
	}

	changed := 0
	for k, v := range RequiredGlobalConfig {
		if existing, ok := config[k].(string); !ok || existing != v {
			config[k] = v
			changed++
		}
	}

	if changed == 0 {
		return 0, nil
	}

	out, err := json.MarshalIndent(config, "", "  ")
	if err != nil {
		return 0, fmt.Errorf("marshaling config: %w", err)
	}

	if err := os.WriteFile(path, append(out, '\n'), 0644); err != nil {
		return 0, fmt.Errorf("writing %s: %w", path, err)
	}

	return changed, nil
}

// EnsureAll runs all ensure functions and returns a summary of changes.
func EnsureAll() error {
	permCount, err := EnsurePermissions()
	if err != nil {
		return fmt.Errorf("ensuring permissions: %w", err)
	}
	if permCount > 0 {
		fmt.Printf("  Added %d tmux permission(s) to %s\n", permCount, SettingsPath())
	}

	envCount, err := EnsureEnv()
	if err != nil {
		return fmt.Errorf("ensuring env vars: %w", err)
	}
	if envCount > 0 {
		fmt.Printf("  Added %d env var(s) to %s\n", envCount, SettingsPath())
	}

	cfgCount, err := EnsureGlobalConfig()
	if err != nil {
		return fmt.Errorf("ensuring global config: %w", err)
	}
	if cfgCount > 0 {
		fmt.Printf("  Set teammateMode=tmux in %s\n", GlobalConfigPath())
	}

	return nil
}

