	"github.com/spf13/cobra"
	"gopkg.in/yaml.v3"
)

func initCmd() *cobra.Command {
	var repoURL string
	var projectPath string

	cmd := &cobra.Command{
		Use:   "init",
		Short: "Initialize a workspace for agent isolation",
		RunE: func(cmd *cobra.Command, args []string) error {
			return runInit(repoURL, projectPath)
		},
	}

	cmd.Flags().StringVar(&repoURL, "repo-url", "", "Git remote URL (default: auto-detect from origin)")
	cmd.Flags().StringVar(&projectPath, "project-path", "", "Path to project repo (default: current directory)")

	return cmd
}

func runInit(repoURL, projectPath string) error {
	// 1. Detect project path
	if projectPath == "" {
		cwd, err := os.Getwd()
		if err != nil {
			return fmt.Errorf("getting cwd: %w", err)
		}
		projectPath = cwd
	}
	absPath, err := filepath.Abs(projectPath)
	if err != nil {
		return fmt.Errorf("resolving project path: %w", err)
	}
	projectPath = absPath

	// 2. Detect repo URL
	if repoURL == "" {
		out, err := exec.Command("git", "-C", projectPath, "remote", "get-url", "origin").Output()
		if err != nil {
			return fmt.Errorf("could not detect repo URL (use --repo-url): %w", err)
		}
		repoURL = strings.TrimSpace(string(out))
	}
	if repoURL == "" {
		return fmt.Errorf("repo URL is empty (use --repo-url)")
	}

	// 3. Detect default branch
	defaultBranch := "main"
	out, err := exec.Command("git", "-C", projectPath, "symbolic-ref", "refs/remotes/origin/HEAD").Output()
	if err == nil {
		ref := strings.TrimSpace(string(out))
		// refs/remotes/origin/main -> main
		if parts := strings.Split(ref, "/"); len(parts) > 0 {
			defaultBranch = parts[len(parts)-1]
		}
	}

	// 4. Derive workspace directory (project-local .agentsea/)
	wsDir := filepath.Join(projectPath, workspace.DirName)

	// 5. Check for existing workspace
	if _, err := os.Stat(filepath.Join(wsDir, "workspace.yaml")); err == nil {
		return fmt.Errorf("workspace already exists at %s", wsDir)
	}

	projectName := filepath.Base(projectPath)
	fmt.Printf("Initializing workspace for %s...\n", projectName)
	fmt.Printf("  Project: %s\n", projectPath)
	fmt.Printf("  Repo:    %s\n", repoURL)
	fmt.Printf("  Branch:  %s\n", defaultBranch)

	// 6. Create workspace layout
	sshDir := filepath.Join(wsDir, "ssh")
	for _, dir := range []string{
		wsDir,
		filepath.Join(wsDir, "agents"),
		sshDir,
	} {
		if err := os.MkdirAll(dir, 0755); err != nil {
			return fmt.Errorf("creating %s: %w", dir, err)
		}
	}

	// 7. Bare clone
	canonicalPath := filepath.Join(wsDir, "canonical")
	fmt.Println("Cloning repository (bare)...")
	cloneOut, err := exec.Command("git", "clone", "--bare", repoURL, canonicalPath).CombinedOutput()
	if err != nil {
		return fmt.Errorf("git clone --bare: %s: %w", cloneOut, err)
	}

	// 8. Install pre-receive hook
	if err := gitops.InstallPreReceiveHook(canonicalPath); err != nil {
		return fmt.Errorf("installing pre-receive hook: %w", err)
	}

	// 9. Generate deploy key
	fmt.Println("Generating deploy key...")
	if err := gitops.GenerateDeployKey(sshDir); err != nil {
		return fmt.Errorf("generating deploy key: %w", err)
	}

	// 10. Write SSH config
	keyPath := filepath.Join(sshDir, "deploy_key")
	if err := gitops.WriteSSHConfig(sshDir, keyPath); err != nil {
		return fmt.Errorf("writing SSH config: %w", err)
	}

	// 11. Write workspace.yaml
	cfg := workspace.Config{
		RepoURL:       repoURL,
		ProjectPath:   projectPath,
		DefaultBranch: defaultBranch,
	}
	yamlData, err := yaml.Marshal(&cfg)
	if err != nil {
		return fmt.Errorf("marshaling workspace config: %w", err)
	}
	if err := os.WriteFile(filepath.Join(wsDir, "workspace.yaml"), yamlData, 0644); err != nil {
		return fmt.Errorf("writing workspace.yaml: %w", err)
	}

	// 12. Add .agentsea/ to .gitignore if not already present
	if err := ensureGitignore(projectPath, workspace.DirName+"/"); err != nil {
		return fmt.Errorf("updating .gitignore: %w", err)
	}

	// 13. Check bwrap
	if _, err := exec.LookPath("bwrap"); err != nil {
		fmt.Println("\n⚠ bwrap not found. Install it:")
		fmt.Println("  sudo apt install bubblewrap")
	} else {
		fmt.Println("✓ bwrap found")
	}

	// 14. Check AppArmor
	checkInitAppArmor()

	// 15. Check claude binary
	seaBin, err := os.Executable()
	if err != nil {
		seaBin = "sea"
	}
	seaBin, _ = filepath.Abs(seaBin)

	if _, err := detect.FindClaudeBinary(); err != nil {
		fmt.Println("⚠ claude binary not found on PATH")
	} else {
		fmt.Println("✓ claude binary found")
	}

	// 16. Print export command
	fmt.Println("\n── Setup ──────────────────────────────────────────")
	fmt.Println("Add to your shell profile:")
	fmt.Printf("  export CLAUDE_CODE_TEAMMATE_COMMAND=\"%s\"\n", filepath.Join(filepath.Dir(seaBin), "sea-teammate-wrapper"))

	// 17. Print deploy key
	pubKey, err := os.ReadFile(filepath.Join(sshDir, "deploy_key.pub"))
	if err == nil {
		fmt.Println("\n── Deploy Key ─────────────────────────────────────")
		fmt.Println("Add this as a deploy key in your repository settings")
		fmt.Println("(Settings → Deploy keys → Add deploy key):")
		fmt.Println()
		fmt.Print(string(pubKey))
	}

