package settings

import (
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
)

func TestRequiredPermissions_NotEmpty(t *testing.T) {
	if len(RequiredPermissions) == 0 {
		t.Error("RequiredPermissions should not be empty")
	}
	for _, p := range RequiredPermissions {
		if p == "" {
			t.Error("permission entry should not be empty")
		}
	}
}

func TestEnsureGlobalConfig_CreatesFile(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)

	n, err := EnsureGlobalConfig()
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if n != len(RequiredGlobalConfig) {
		t.Errorf("expected %d keys set, got %d", len(RequiredGlobalConfig), n)
	}

	data, _ := os.ReadFile(filepath.Join(home, ".claude.json"))
	var config map[string]interface{}
	json.Unmarshal(data, &config)

	if config["teammateMode"] != "tmux" {
		t.Errorf("teammateMode = %v, want tmux", config["teammateMode"])
	}
}

func TestEnsureGlobalConfig_PreservesExisting(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)

	existing := map[string]interface{}{
		"apiKey":       "sk-test-123",
		"teammateMode": "auto",
	}
	data, _ := json.MarshalIndent(existing, "", "  ")
	os.WriteFile(filepath.Join(home, ".claude.json"), data, 0644)

	n, err := EnsureGlobalConfig()
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if n != 1 {
		t.Errorf("expected 1 key changed, got %d", n)
	}

	result, _ := os.ReadFile(filepath.Join(home, ".claude.json"))
	var config map[string]interface{}
	json.Unmarshal(result, &config)

	if config["apiKey"] != "sk-test-123" {
		t.Error("apiKey should be preserved")
	}
	if config["teammateMode"] != "tmux" {
		t.Errorf("teammateMode = %v, want tmux", config["teammateMode"])
	}
}

func TestEnsureGlobalConfig_Idempotent(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)

	n1, _ := EnsureGlobalConfig()
	if n1 == 0 {
		t.Error("first call should change keys")
	}

	n2, _ := EnsureGlobalConfig()
	if n2 != 0 {
		t.Errorf("second call should change 0 keys, got %d", n2)
	}
}

