	if err := json.Unmarshal(data, &settings); err != nil {
		t.Fatalf("parsing settings: %v", err)
	}

	perms, ok := settings["permissions"].(map[string]interface{})
	if !ok {
		t.Fatal("missing permissions key")
	}
	allow, ok := perms["allow"].([]interface{})
	if !ok {
		t.Fatal("missing allow key")
	}
	if len(allow) != len(RequiredPermissions) {
		t.Errorf("expected %d allow entries, got %d", len(RequiredPermissions), len(allow))
	}
}

func TestEnsurePermissions_Idempotent(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)

	// First call adds permissions
	n1, err := EnsurePermissions()
	if err != nil {
		t.Fatalf("first call: %v", err)
	}
	if n1 == 0 {
		t.Error("first call should have added permissions")
	}

	// Second call adds nothing
	n2, err := EnsurePermissions()
	if err != nil {
		t.Fatalf("second call: %v", err)
	}
	if n2 != 0 {
		t.Errorf("second call should add 0 permissions, got %d", n2)
	}
}

func TestEnsurePermissions_PreservesExisting(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)

	// Create settings with existing permissions
	dir := filepath.Join(home, ".claude")
	os.MkdirAll(dir, 0755)

	existing := map[string]interface{}{
		"permissions": map[string]interface{}{
			"allow": []interface{}{
				"Bash(git status:*)",
				"Bash(go test:*)",
			},
		},
		"hooks": map[string]interface{}{
			"PreCompact": "something",
		},
	}
	data, _ := json.MarshalIndent(existing, "", "  ")
	os.WriteFile(filepath.Join(dir, "settings.json"), data, 0644)

	n, err := EnsurePermissions()
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if n != len(RequiredPermissions) {
		t.Errorf("expected %d added, got %d", len(RequiredPermissions), n)
	}

	// Verify existing entries preserved
	result, _ := os.ReadFile(filepath.Join(dir, "settings.json"))
	var settings map[string]interface{}
	json.Unmarshal(result, &settings)

	perms := settings["permissions"].(map[string]interface{})
	allow := perms["allow"].([]interface{})

	// Should have original 2 + new ones
	expectedLen := 2 + len(RequiredPermissions)
	if len(allow) != expectedLen {
		t.Errorf("expected %d allow entries, got %d", expectedLen, len(allow))
	}

	// Verify hooks not clobbered
	if _, ok := settings["hooks"]; !ok {
		t.Error("hooks key should be preserved")
	}
}

func TestEnsureEnv_AddsVars(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)

	dir := filepath.Join(home, ".claude")
	os.MkdirAll(dir, 0755)
	os.WriteFile(filepath.Join(dir, "settings.json"), []byte("{}"), 0644)

	n, err := EnsureEnv()
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if n != len(RequiredEnv) {
		t.Errorf("expected %d env vars added, got %d", len(RequiredEnv), n)
	}
}

func TestEnsureGlobalConfig_SetsTeammateMode(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)

	// No .claude.json exists
	n, err := EnsureGlobalConfig()
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if n != len(RequiredGlobalConfig) {
		t.Errorf("expected %d keys set, got %d", len(RequiredGlobalConfig), n)
	}

