	data, _ := os.ReadFile(filepath.Join(home, ".claude.json"))
	var config map[string]interface{}
	json.Unmarshal(data, &config)

	if config["teammateMode"] != "tmux" {
		t.Errorf("teammateMode = %v, want tmux", config["teammateMode"])
	}
}

func TestEnsureGlobalConfig_PreservesExisting(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)

	existing := map[string]interface{}{
		"apiKey":       "sk-test-123",
		"teammateMode": "auto",
