package cli

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"syscall"

	"github.com/spf13/cobra"

	"github.com/agentsea/agentsea/internal/detect"
	"github.com/agentsea/agentsea/internal/settings"
)

func claudeCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "claude [-- claude-args...]",
		Short: "Launch Claude Code with agent sandboxing enabled",
		Long: `Launches Claude Code with CLAUDE_CODE_TEAMMATE_COMMAND set to "sea teammate-wrapper".
All arguments after -- are passed through to claude.

Aborts if CLAUDE_CODE_TEAMMATE_COMMAND is already set in the environment.`,
		DisableFlagParsing: true,
		RunE: func(cmd *cobra.Command, args []string) error {
			return runClaude(args)
		},
	}
}

// claudeConfig holds resolved paths from preflight checks.
type claudeConfig struct {
	ClaudeBin string
	SeaBin    string
	Args      []string // args to pass to claude
}

// claudePreflight validates the environment and resolves paths.
// Separated from runClaude so it can be tested without syscall.Exec.
func claudePreflight(args []string) (*claudeConfig, error) {
	// Abort if CLAUDE_CODE_TEAMMATE_COMMAND is already set
	if val := os.Getenv("CLAUDE_CODE_TEAMMATE_COMMAND"); val != "" {
		return nil, fmt.Errorf("CLAUDE_CODE_TEAMMATE_COMMAND is already set to %q — cannot override", val)
	}

	// Find claude binary
	claudeBin, err := detect.FindClaudeBinary()
	if err != nil {
		return nil, fmt.Errorf("finding claude binary: %w", err)
	}

	// Resolve sea binary path for the env var
	seaBin, err := os.Executable()
	if err != nil {
		return nil, fmt.Errorf("resolving sea binary path: %w", err)
	}

	// Find bwrap to verify it exists before launching
	if _, err := exec.LookPath("bwrap"); err != nil {
		return nil, fmt.Errorf("bwrap not found on PATH — install with: sudo apt install bubblewrap")
	}

	// Strip leading "--" if present (cobra passes it through with DisableFlagParsing)
	claudeArgs := args
	if len(claudeArgs) > 0 && claudeArgs[0] == "--" {
		claudeArgs = claudeArgs[1:]
	}

	return &claudeConfig{
		ClaudeBin: claudeBin,
		SeaBin:    seaBin,
		Args:      claudeArgs,
	}, nil
}

func runClaude(args []string) error {
	cfg, err := claudePreflight(args)
	if err != nil {
		return err
	}

	// Build environment with CLAUDE_CODE_TEAMMATE_COMMAND injected.
	// Must be a single executable path — use sea-teammate-wrapper (installed alongside sea).
	wrapperBin := filepath.Join(filepath.Dir(cfg.SeaBin), "sea-teammate-wrapper")
	env := os.Environ()
	env = append(env, fmt.Sprintf("CLAUDE_CODE_TEAMMATE_COMMAND=%s", wrapperBin))

	// Ensure teammateMode=tmux in ~/.claude.json so CLAUDE_CODE_TEAMMATE_COMMAND
	// is actually used (v2.1.71+ defaults to in-process which bypasses it).
	if err := settings.EnsureGlobalConfig(); err != nil {
		fmt.Fprintf(os.Stderr, "Warning: could not update ~/.claude.json: %v\n", err)
	}

	// Inject --allowedTools for tmux commands so the lead agent doesn't
	// prompt for permission on every teammate management operation.
	// This is non-invasive: it doesn't modify the user's settings.json.
	allowedTools := strings.Join(settings.RequiredPermissions, " ")
	claudeArgs := append([]string{"--allowedTools", allowedTools}, cfg.Args...)

	// Build argv: claude [--allowedTools ...] [user args...]
	argv := append([]string{cfg.ClaudeBin}, claudeArgs...)

	fmt.Printf("Starting Claude Code with agent sandboxing enabled\n")
	fmt.Printf("  claude: %s\n", cfg.ClaudeBin)
	fmt.Printf("  wrapper: %s\n", wrapperBin)
	fmt.Println()

	// exec replaces the current process
	return syscall.Exec(cfg.ClaudeBin, argv, env)
}

