41→}
42→
43→// EnsureGlobalConfig ensures required keys are set in ~/.claude.json.
44→// Returns the number of keys added/changed.
45→func EnsureGlobalConfig() (int, error) {
46→	path := GlobalConfigPath()
47→
48→	data, err := os.ReadFile(path)
49→	if err != nil && !os.IsNotExist(err) {
50→		return 0, fmt.Errorf("reading %s: %w", path, err)
51→	}
52→
53→	var config map[string]interface{}
54→	if len(data) > 0 {
55→		if err := json.Unmarshal(data, &config); err != nil {
56→			return 0, fmt.Errorf("parsing %s: %w", path, err)
57→		}
58→	}
59→	if config == nil {
60→		config = make(map[string]interface{})
61→	}
62→
63→	changed := 0
64→	for k, v := range RequiredGlobalConfig {
65→		if existing, ok := config[k].(string); !ok || existing != v {
66→			config[k] = v
67→			changed++
68→		}
69→	}
70→
71→	if changed == 0 {
72→		return 0, nil
73→	}
74→
75→	out, err := json.MarshalIndent(config, "", "  ")
76→	if err != nil {
77→		return 0, fmt.Errorf("marshaling config: %w", err)
78→	}
79→
80→	if err := os.WriteFile(path, append(out, '\n'), 0644); err != nil {
81→		return 0, fmt.Errorf("writing %s: %w", path, err)
82→	}
83→
84→	return changed, nil
85→}
