 19→func teammateWrapperCmd() *cobra.Command {
 20→	return &cobra.Command{
 21→		Use:                "teammate-wrapper",
 22→		Short:              "Wrap a teammate spawn in a bwrap sandbox",
 23→		Hidden:             true,
 24→		DisableFlagParsing: true,
 25→		RunE: func(cmd *cobra.Command, args []string) error {
 26→			return runTeammateWrapper(args)
 27→		},
 28→	}
 29→}
 30→
 31→func runTeammateWrapper(args []string) error {
 32→	// 1. Parse teammate flags
 33→	parsed, err := flags.Parse(args)
 34→	if err != nil {
 35→		return fmt.Errorf("parsing flags: %w", err)
 36→	}
 37→
 38→	// 2. Find workspace config from cwd
 39→	ws, err := workspace.Detect()
 40→	if err != nil {
 41→		return fmt.Errorf("detecting workspace: %w", err)
 42→	}
 43→
 44→	// 3. Provision agent workspace (idempotent — skip if already exists)
 45→	agentRepo := ws.AgentRepoPath(parsed.AgentName)
 46→	agentSSH := ws.AgentSSHPath(parsed.AgentName)
 47→
 48→	if _, err := os.Stat(agentRepo); os.IsNotExist(err) {
 49→		if err := gitops.CloneAgent(ws.CanonicalPath(), agentRepo, parsed.AgentName); err != nil {
 50→			return fmt.Errorf("cloning agent repo: %w", err)
 51→		}
 52→		if err := gitops.WriteAgentContext(agentRepo); err != nil {
 53→			return fmt.Errorf("writing agent context: %w", err)
 54→		}
 55→		if err := gitops.InstallPrePushHook(agentRepo); err != nil {
 56→			return fmt.Errorf("installing pre-push hook: %w", err)
 57→		}
 58→		if err := gitops.GenerateDeployKey(agentSSH); err != nil {
 59→			return fmt.Errorf("generating deploy key: %w", err)
 60→		}
 61→		if err := gitops.WriteSSHConfig(agentSSH, filepath.Join(agentSSH, "deploy_key")); err != nil {
 62→			return fmt.Errorf("writing ssh config: %w", err)
 63→		}
 64→	}
 65→
 66→	// 4. Find claude binary
 67→	claudeBin, err := detect.FindClaudeBinary()
 68→	if err != nil {
 69→		return fmt.Errorf("finding claude binary: %w", err)
 70→	}
 71→	claudeDir := detect.ClaudeBinaryDir(claudeBin)
 72→
 73→	// 5. Prepare writable .claude copy (dereference symlinks)
 74→	claudeHome, err := prepareClaudeHome(ws, parsed.AgentName, parsed.TeamName)
 75→	if err != nil {
 76→		return fmt.Errorf("preparing claude home: %w", err)
 77→	}
 78→
 79→	// 6. Build bwrap config
 80→	home := os.Getenv("HOME")
 81→	cfg := sandbox.SandboxConfig{
 82→		AgentRepo:    agentRepo,
 83→		TeamMailbox:  ws.TeamMailboxPath(parsed.TeamName),
 84→		ClaudeHome:   claudeHome,
 85→		ClaudeBinDir: claudeDir,
 86→		AgentSSHDir:  agentSSH,
 87→		ExtraRO:      ws.Config.ExtraROMounts,
 88→		ExtraRW:      ws.Config.ExtraRWMounts,
 89→		Home:         home,
 90→		User:         os.Getenv("USER"),
 91→		WorkDir:      agentRepo,
 92→	}
 93→
 94→	// Only mount .claude.json if it exists
 95→	claudeJSON := filepath.Join(home, ".claude.json")
 96→	if _, err := os.Stat(claudeJSON); err == nil {
 97→		cfg.ClaudeJSON = claudeJSON
 98→	}
 99→
100→	if err := cfg.Validate(); err != nil {
101→		return fmt.Errorf("invalid sandbox config: %w", err)
102→	}
103→
104→	// Ensure team mailbox directory exists
105→	if err := os.MkdirAll(ws.TeamMailboxPath(parsed.TeamName), 0755); err != nil {
106→		return fmt.Errorf("creating team mailbox dir: %w", err)
107→	}
108→
109→	// 7. Inject agent profile flags (model, effort) if configured
110→	finalArgs := injectProfileFlags(parsed.AgentName, parsed.AllArgs, ws.Config.AgentProfiles)
111→
112→	// 8. Inject --print "start" so Claude runs in non-interactive mode.
113→	// setsid (needed to prevent SIGTTOU from bwrap's process group)
114→	// detaches the controlling terminal, making stdout non-TTY.
115→	// Claude in non-interactive mode requires --print with a prompt.
116→	// The teammate's actual instructions come via the mailbox, not this prompt.
117→	finalArgs = append(finalArgs, "--print", "start")
118→
119→	// 9. Build full command and exec
120→	bwrapArgs := cfg.Args()
121→	bwrapArgs = append(bwrapArgs, "--", claudeBin)
122→	bwrapArgs = append(bwrapArgs, finalArgs...)
123→
124→	return sandbox.ExecSetsidBwrap(bwrapArgs)
125→}
126→
127→// injectProfileFlags prepends --model and --effort flags from the agent profile
128→// if the lead hasn't already specified them explicitly. Agent-specific profiles
129→// take priority over the "default" profile.
130→func injectProfileFlags(agentName string, allArgs []string, profiles map[string]workspace.AgentProfile) []string {
131→	if len(profiles) == 0 {
132→		return allArgs
133→	}
134→
135→	profile, ok := profiles[agentName]
136→	if !ok {
137→		profile, ok = profiles["default"]
138→		if !ok {
139→			return allArgs
140→		}
141→	}
142→
143→	hasModel := hasFlag(allArgs, "--model")
144→	hasEffort := hasFlag(allArgs, "--effort")
145→
146→	var inject []string
147→	if profile.Model != "" && !hasModel {
148→		inject = append(inject, "--model", profile.Model)
149→	}
150→	if profile.Effort != "" && !hasEffort {
151→		inject = append(inject, "--effort", profile.Effort)
152→	}
153→
154→	if len(inject) == 0 {
155→		return allArgs
156→	}
157→
158→	result := make([]string, 0, len(inject)+len(allArgs))
159→	result = append(result, inject...)
160→	result = append(result, allArgs...)
161→	return result
162→}
163→
164→// hasFlag checks whether a flag (e.g. "--model") is already present in args,
165→// handling both "--flag value" and "--flag=value" forms.
166→func hasFlag(args []string, flag string) bool {
167→	for _, arg := range args {
168→		if arg == flag || strings.HasPrefix(arg, flag+"=") {
169→			return true
170→		}
171→	}
172→	return false
173→}
174→
175→// prepareClaudeHome creates a writable copy of ~/.claude/ with symlinks dereferenced.
176→// Returns the path to the copy.
177→func prepareClaudeHome(ws *workspace.Workspace, agentName, teamName string) (string, error) {
178→	target := filepath.Join(ws.Dir, "agents", agentName, "claude-home")
179→
180→	if _, err := os.Stat(target); os.IsNotExist(err) {
181→		src := filepath.Join(os.Getenv("HOME"), ".claude")
182→
183→		// cp -aL dereferences symlinks (settings.json, CLAUDE.md may be symlinks to dotfiles)
184→		// Fall back to cp -a if -aL fails, then to mkdir as last resort.
185→		if out, err := exec.Command("cp", "-aL", src, target).CombinedOutput(); err != nil {
186→			if out2, err2 := exec.Command("cp", "-a", src, target).CombinedOutput(); err2 != nil {
187→				if err3 := os.MkdirAll(target, 0755); err3 != nil {
188→					return "", fmt.Errorf("cp -aL: %s, cp -a: %s, mkdir: %w", out, out2, err3)
189→				}
190→			}
191→		}
192→	}
193→
194→	// Ensure teams/<teamName> subdir exists inside the copy for mailbox config
195→	teamsDir := filepath.Join(target, "teams", teamName)
196→	if err := os.MkdirAll(teamsDir, 0755); err != nil {
197→		return "", fmt.Errorf("creating teams dir in claude home: %w", err)
198→	}
199→
200→	// Pre-create the project directory for the agent repo so Claude
201→	// recognizes it as a trusted workspace and skips the trust dialog.
202→	// Claude encodes paths by replacing "/" with "-" and stripping the leading "/".
203→	agentRepo := ws.AgentRepoPath(agentName)
