package cli

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"

	"github.com/spf13/cobra"

	"github.com/agentsea/agentsea/internal/detect"
	"github.com/agentsea/agentsea/internal/flags"
	"github.com/agentsea/agentsea/internal/gitops"
	"github.com/agentsea/agentsea/internal/sandbox"
	"github.com/agentsea/agentsea/internal/workspace"
)

func teammateWrapperCmd() *cobra.Command {
	return &cobra.Command{
		Use:                "teammate-wrapper",
		Short:              "Wrap a teammate spawn in a bwrap sandbox",
		Hidden:             true,
		DisableFlagParsing: true,
		RunE: func(cmd *cobra.Command, args []string) error {
			return runTeammateWrapper(args)
		},
	}
}

func runTeammateWrapper(args []string) error {
	// 1. Parse teammate flags
	parsed, err := flags.Parse(args)
	if err != nil {
		return fmt.Errorf("parsing flags: %w", err)
	}

	// 2. Find workspace config from cwd
	ws, err := workspace.Detect()
	if err != nil {
		return fmt.Errorf("detecting workspace: %w", err)
	}

	// 3. Provision agent workspace (idempotent — skip if already exists)
	agentRepo := ws.AgentRepoPath(parsed.AgentName)
	agentSSH := ws.AgentSSHPath(parsed.AgentName)

	if _, err := os.Stat(agentRepo); os.IsNotExist(err) {
		if err := gitops.CloneAgent(ws.CanonicalPath(), agentRepo, parsed.AgentName); err != nil {
			return fmt.Errorf("cloning agent repo: %w", err)
		}
		if err := gitops.WriteAgentContext(agentRepo); err != nil {
			return fmt.Errorf("writing agent context: %w", err)
		}
		if err := gitops.InstallPrePushHook(agentRepo); err != nil {
			return fmt.Errorf("installing pre-push hook: %w", err)
		}
		if err := gitops.GenerateDeployKey(agentSSH); err != nil {
			return fmt.Errorf("generating deploy key: %w", err)
		}
		if err := gitops.WriteSSHConfig(agentSSH, filepath.Join(agentSSH, "deploy_key")); err != nil {
			return fmt.Errorf("writing ssh config: %w", err)
		}
	}

	// 4. Find claude binary
	claudeBin, err := detect.FindClaudeBinary()
	if err != nil {
		return fmt.Errorf("finding claude binary: %w", err)
	}
	claudeDir := detect.ClaudeBinaryDir(claudeBin)

	// 5. Prepare writable .claude copy (dereference symlinks)
	claudeHome, err := prepareClaudeHome(ws, parsed.AgentName, parsed.TeamName)
	if err != nil {
		return fmt.Errorf("preparing claude home: %w", err)
	}

	// 6. Build bwrap config
	home := os.Getenv("HOME")
	cfg := sandbox.SandboxConfig{
		AgentRepo:    agentRepo,
		TeamMailbox:  ws.TeamMailboxPath(parsed.TeamName),
		ClaudeHome:   claudeHome,
		ClaudeBinDir: claudeDir,
		AgentSSHDir:  agentSSH,
		ExtraRO:      ws.Config.ExtraROMounts,
		ExtraRW:      ws.Config.ExtraRWMounts,
		Home:         home,
		User:         os.Getenv("USER"),
		WorkDir:      agentRepo,
	}

	// Only mount .claude.json if it exists
	claudeJSON := filepath.Join(home, ".claude.json")
	if _, err := os.Stat(claudeJSON); err == nil {
		cfg.ClaudeJSON = claudeJSON
	}

	if err := cfg.Validate(); err != nil {
		return fmt.Errorf("invalid sandbox config: %w", err)
	}

	// Ensure team mailbox directory exists
	if err := os.MkdirAll(ws.TeamMailboxPath(parsed.TeamName), 0755); err != nil {
		return fmt.Errorf("creating team mailbox dir: %w", err)
	}

	// 7. Inject agent profile flags (model, effort) if configured
	finalArgs := injectProfileFlags(parsed.AgentName, parsed.AllArgs, ws.Config.AgentProfiles)

	// 8. Inject --print "start" so Claude runs in non-interactive mode.
	// setsid (needed to prevent SIGTTOU from bwrap's process group)
	// detaches the controlling terminal, making stdout non-TTY.
	// Claude in non-interactive mode requires --print with a prompt.
	// The teammate's actual instructions come via the mailbox, not this prompt.
	finalArgs = append(finalArgs, "--print", "start")

	// 9. Build full command and exec
	bwrapArgs := cfg.Args()
	bwrapArgs = append(bwrapArgs, "--", claudeBin)
	bwrapArgs = append(bwrapArgs, finalArgs...)

	return sandbox.ExecSetsidBwrap(bwrapArgs)
}

// injectProfileFlags prepends --model and --effort flags from the agent profile
// if the lead hasn't already specified them explicitly. Agent-specific profiles
// take priority over the "default" profile.
func injectProfileFlags(agentName string, allArgs []string, profiles map[string]workspace.AgentProfile) []string {
	if len(profiles) == 0 {
		return allArgs
	}

	profile, ok := profiles[agentName]
	if !ok {
		profile, ok = profiles["default"]
		if !ok {
			return allArgs
		}
	}

	hasModel := hasFlag(allArgs, "--model")
	hasEffort := hasFlag(allArgs, "--effort")

	var inject []string
	if profile.Model != "" && !hasModel {
		inject = append(inject, "--model", profile.Model)
	}
	if profile.Effort != "" && !hasEffort {
		inject = append(inject, "--effort", profile.Effort)
	}

	if len(inject) == 0 {
		return allArgs
	}

	result := make([]string, 0, len(inject)+len(allArgs))
	result = append(result, inject...)
	result = append(result, allArgs...)
	return result
}

// hasFlag checks whether a flag (e.g. "--model") is already present in args,
// handling both "--flag value" and "--flag=value" forms.
func hasFlag(args []string, flag string) bool {
	for _, arg := range args {
		if arg == flag || strings.HasPrefix(arg, flag+"=") {
			return true
		}
	}
	return false
}

// prepareClaudeHome creates a writable copy of ~/.claude/ with symlinks dereferenced.
// Returns the path to the copy.
func prepareClaudeHome(ws *workspace.Workspace, agentName, teamName string) (string, error) {
	target := filepath.Join(ws.Dir, "agents", agentName, "claude-home")

	if _, err := os.Stat(target); os.IsNotExist(err) {
		src := filepath.Join(os.Getenv("HOME"), ".claude")

		// cp -aL dereferences symlinks (settings.json, CLAUDE.md may be symlinks to dotfiles)
		// Fall back to cp -a if -aL fails, then to mkdir as last resort.
		if out, err := exec.Command("cp", "-aL", src, target).CombinedOutput(); err != nil {
			if out2, err2 := exec.Command("cp", "-a", src, target).CombinedOutput(); err2 != nil {
				if err3 := os.MkdirAll(target, 0755); err3 != nil {
					return "", fmt.Errorf("cp -aL: %s, cp -a: %s, mkdir: %w", out, out2, err3)
				}
			}
		}
	}

	// Ensure teams/<teamName> subdir exists inside the copy for mailbox config
	teamsDir := filepath.Join(target, "teams", teamName)
	if err := os.MkdirAll(teamsDir, 0755); err != nil {
		return "", fmt.Errorf("creating teams dir in claude home: %w", err)
	}

	// Pre-create the project directory for the agent repo so Claude
	// recognizes it as a trusted workspace and skips the trust dialog.
	// Claude encodes paths by replacing "/" with "-" and stripping the leading "/".
	agentRepo := ws.AgentRepoPath(agentName)
	encodedPath := strings.ReplaceAll(agentRepo, "/", "-")
	projectDir := filepath.Join(target, "projects", encodedPath)
	if err := os.MkdirAll(projectDir, 0755); err != nil {
		return "", fmt.Errorf("creating project dir in claude home: %w", err)
	}

	return target, nil
}

package sandbox

import (
	"fmt"
	"path"
	"path/filepath"
)

// SandboxConfig defines the mount points and environment for a bwrap sandbox.
type SandboxConfig struct {
	AgentRepo    string   // bind rw — agent's git clone
	TeamMailbox  string   // bind rw — ~/.claude/teams/<team>/
	ClaudeHome   string   // bind rw — writable copy of ~/.claude/
	ClaudeBinDir string   // ro-bind — claude binary directory
	ClaudeJSON   string   // ro-bind — ~/.claude.json (API credentials), optional
	AgentSSHDir  string   // ro-bind — agent's deploy key as ~/.ssh/, optional
	ExtraRO      []string // ro-bind — user-configured extra read-only mounts
	ExtraRW      []string // bind    — user-configured extra read-write mounts
	Home         string   // $HOME value inside sandbox
	User         string   // $USER value inside sandbox
	WorkDir      string   // --chdir target (agent repo)
}

// Validate checks that required fields are non-empty and absolute paths.
func (c *SandboxConfig) Validate() error {
	checks := map[string]string{
		"Home":         c.Home,
		"AgentRepo":    c.AgentRepo,
		"ClaudeHome":   c.ClaudeHome,
		"ClaudeBinDir": c.ClaudeBinDir,
		"TeamMailbox":  c.TeamMailbox,
		"WorkDir":      c.WorkDir,
	}
	for name, val := range checks {
		if val == "" {
			return fmt.Errorf("SandboxConfig.%s must not be empty", name)
		}
		if !filepath.IsAbs(val) {
			return fmt.Errorf("SandboxConfig.%s must be an absolute path, got %q", name, val)
		}
	}
	return nil
}

// Args returns the full bwrap argument list.
// Order matters: later mounts overlay earlier ones.
func (c *SandboxConfig) Args() []string {
	args := []string{
		// Base: read-only root, then tmpfs overlays for isolation.
		// Order matters: later mounts overlay earlier ones, so tmpfs
		// must come before any bind mounts under those paths.
		"--ro-bind", "/", "/",
		"--tmpfs", c.Home,
		"--tmpfs", "/tmp",
		"--proc", "/proc",
		"--dev", "/dev",
		// Writable bind mounts (after tmpfs so they overlay correctly)
		"--bind", c.ClaudeHome, path.Join(c.Home, ".claude"),
		"--bind", c.AgentRepo, c.AgentRepo,
		"--bind", c.TeamMailbox, c.TeamMailbox,
		"--ro-bind", c.ClaudeBinDir, c.ClaudeBinDir,
		"--setenv", "HOME", c.Home,
		"--setenv", "USER", c.User,
		"--setenv", "SSH_AUTH_SOCK", "",
	}

	if c.ClaudeJSON != "" {
		args = append(args, "--ro-bind", c.ClaudeJSON, path.Join(c.Home, ".claude.json"))
	}

	if c.AgentSSHDir != "" {
		args = append(args, "--ro-bind", c.AgentSSHDir, path.Join(c.Home, ".ssh"))
	}

	for _, p := range c.ExtraRO {
		args = append(args, "--ro-bind", p, p)
	}
	for _, p := range c.ExtraRW {
		args = append(args, "--bind", p, p)
	}

	args = append(args, "--chdir", c.WorkDir)

	return args
}

package sandbox

import (
	"fmt"
	"os"
	"os/exec"
	"syscall"
)

// ExecBwrap replaces the current process with bwrap [args].
//
// In tmux teammate mode (the primary use case), the process runs as the
// foreground process group in a tmux pane, so no setsid is needed. Using
// setsid would detach the controlling terminal, causing Claude to see
// !process.stdout.isTTY and enter non-interactive mode, which breaks
// teammate spawning.
//
// This function does not return on success.
func ExecBwrap(bwrapArgs []string) error {
	bwrapPath, err := exec.LookPath("bwrap")
	if err != nil {
		return fmt.Errorf("bwrap not found: %w", err)
	}

	argv := buildBwrapArgv(bwrapPath, bwrapArgs)
	return syscall.Exec(bwrapPath, argv, os.Environ())
}

// ExecSetsidBwrap replaces the current process with setsid bwrap [args].
// setsid creates a new session, preventing SIGTTOU when bwrap's process
// group is not the foreground group. However, this detaches the controlling
// terminal, making Claude non-interactive. Use ExecBwrap instead when
// the process will be the foreground process (e.g., in a tmux pane).
//
// This function does not return on success.
func ExecSetsidBwrap(bwrapArgs []string) error {
	setsidPath, err := exec.LookPath("setsid")
	if err != nil {
		return fmt.Errorf("setsid not found: %w", err)
	}

	bwrapPath, err := exec.LookPath("bwrap")
	if err != nil {
		return fmt.Errorf("bwrap not found: %w", err)
	}

	argv := buildSetsidArgv(setsidPath, bwrapPath, bwrapArgs)
	return syscall.Exec(setsidPath, argv, os.Environ())
}

// buildBwrapArgv constructs the argv slice for syscall.Exec:
// argv[0] = "bwrap", argv[1:] = bwrapArgs.
func buildBwrapArgv(bwrapPath string, bwrapArgs []string) []string {
	argv := make([]string, 0, 1+len(bwrapArgs))
	argv = append(argv, "bwrap")
	argv = append(argv, bwrapArgs...)
	return argv
}

// buildSetsidArgv constructs the argv slice for syscall.Exec:
// argv[0] = "setsid", argv[1] = bwrapPath, argv[2:] = bwrapArgs.
func buildSetsidArgv(setsidPath, bwrapPath string, bwrapArgs []string) []string {
	argv := make([]string, 0, 2+len(bwrapArgs))
	argv = append(argv, "setsid", bwrapPath)
	argv = append(argv, bwrapArgs...)
	return argv
}

package cli

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"time"

	"github.com/spf13/cobra"
	"gopkg.in/yaml.v3"

	"github.com/agentsea/agentsea/internal/detect"
	"github.com/agentsea/agentsea/internal/workspace"
)

func smokeCmd() *cobra.Command {
	var timeout time.Duration

	cmd := &cobra.Command{
		Use:   "smoke",
		Short: "End-to-end smoke test of teammate sandboxing",
		Long: `Creates a temporary project, launches Claude Code interactively in a PTY
with sandboxing enabled, and instructs it to spawn a teammate that verifies
its bwrap sandbox environment.

The lead agent spawns a real teammate via CLAUDE_CODE_TEAMMATE_COMMAND,
which goes through the full teammate-wrapper → bwrap pipeline.

Requires no existing repos or network connection.`,
		RunE: func(cmd *cobra.Command, args []string) error {
			return runSmoke(timeout)
		},
	}

	cmd.Flags().DurationVar(&timeout, "timeout", 5*time.Minute, "Maximum time to wait for smoke test")
	return cmd
}

// smokeConfig holds resolved paths for the smoke test environment.
type smokeConfig struct {
	TmpDir     string
	ClaudeBin  string
	SeaBin     string
	WrapperBin string // path to the teammate-wrapper shell script
}

// smokePreflight validates the environment and creates the temp project.
func smokePreflight() (*smokeConfig, error) {
	claudeBin, err := detect.FindClaudeBinary()
	if err != nil {
		return nil, fmt.Errorf("finding claude binary: %w", err)
	}

	seaBin, err := os.Executable()
	if err != nil {
		return nil, fmt.Errorf("resolving sea binary path: %w", err)
	}

	if _, err := exec.LookPath("bwrap"); err != nil {
		return nil, fmt.Errorf("bwrap not found on PATH — install with: sudo apt install bubblewrap")
	}

	tmpDir, err := os.MkdirTemp("", "sea-smoke-*")
	if err != nil {
		return nil, fmt.Errorf("creating temp dir: %w", err)
	}

	return &smokeConfig{
		TmpDir:    tmpDir,
		ClaudeBin: claudeBin,
		SeaBin:    seaBin,
	}, nil
}

// smokeSetup initializes a self-contained git repo and workspace with no
// network access or pre-existing repos required.
func smokeSetup(cfg *smokeConfig) error {
	for name, content := range map[string]string{
		"CLAUDE.md": smokeClaudeMD,
		"README.md": "# Smoke Test Project\n",
	} {
		if err := os.WriteFile(filepath.Join(cfg.TmpDir, name), []byte(content), 0644); err != nil {
			return fmt.Errorf("writing %s: %w", name, err)
		}
	}

	gitEnv := append(os.Environ(),
		"GIT_AUTHOR_NAME=sea-smoke",
		"GIT_AUTHOR_EMAIL=smoke@test",
		"GIT_COMMITTER_NAME=sea-smoke",
		"GIT_COMMITTER_EMAIL=smoke@test",
	)
	for _, args := range [][]string{
		{"git", "init", "-q"},
		{"git", "add", "."},
		{"git", "commit", "-q", "-m", "smoke test init"},
	} {
		cmd := exec.Command(args[0], args[1:]...)
		cmd.Dir = cfg.TmpDir
		cmd.Env = gitEnv
		if out, err := cmd.CombinedOutput(); err != nil {
			return fmt.Errorf("running %v: %s: %w", args, out, err)
		}
	}

	wsDir := filepath.Join(cfg.TmpDir, workspace.DirName)
	for _, dir := range []string{
		wsDir,
		filepath.Join(wsDir, "agents"),
		filepath.Join(wsDir, "ssh"),
	} {
		if err := os.MkdirAll(dir, 0755); err != nil {
			return fmt.Errorf("creating %s: %w", dir, err)
		}
	}

	canonicalPath := filepath.Join(wsDir, "canonical")
	cmd := exec.Command("git", "clone", "--bare", cfg.TmpDir, canonicalPath)
	if out, err := cmd.CombinedOutput(); err != nil {
		return fmt.Errorf("git clone --bare: %s: %w", out, err)
	}

	wsCfg := workspace.Config{
		RepoURL:       cfg.TmpDir,
		ProjectPath:   cfg.TmpDir,
		DefaultBranch: "main",
	}
	yamlData, err := yaml.Marshal(&wsCfg)
	if err != nil {
		return fmt.Errorf("marshaling workspace config: %w", err)
	}
	if err := os.WriteFile(filepath.Join(wsDir, "workspace.yaml"), yamlData, 0644); err != nil {
		return fmt.Errorf("writing workspace.yaml: %w", err)
	}

	// Create a wrapper script for CLAUDE_CODE_TEAMMATE_COMMAND.
	// The env var must be a single executable path, not "sea teammate-wrapper".
	cfg.WrapperBin = filepath.Join(cfg.TmpDir, "teammate-wrapper")
	logFile := filepath.Join(cfg.TmpDir, "wrapper.log")
	// Log diagnostics to file WITHOUT redirecting stdout/stderr globally.
	// Claude inside bwrap needs stdout to be a TTY for interactive mode.
	wrapperContent := fmt.Sprintf("#!/bin/sh\necho \"[wrapper] invoked at $(date)\" >> %q\necho \"[wrapper] args: $@\" >> %q\nexec %q teammate-wrapper \"$@\"\n",
		logFile, logFile, cfg.SeaBin)
	if err := os.WriteFile(cfg.WrapperBin, []byte(wrapperContent), 0755); err != nil {
		return fmt.Errorf("writing teammate-wrapper script: %w", err)
	}

	return nil
}

func runSmoke(timeout time.Duration) error {
	cfg, err := smokePreflight()
	if err != nil {
		return err
	}

	fmt.Printf("Setting up smoke test in %s\n", cfg.TmpDir)

	if err := smokeSetup(cfg); err != nil {
		os.RemoveAll(cfg.TmpDir)
		return err
	}

	fmt.Printf("  claude:  %s\n", cfg.ClaudeBin)
	fmt.Printf("  wrapper: %s\n", cfg.WrapperBin)
	fmt.Printf("  project: %s\n", cfg.TmpDir)
	fmt.Printf("  timeout: %s\n", timeout)
	fmt.Println()
	fmt.Printf("Clean up after: rm -rf %s\n", cfg.TmpDir)
	fmt.Println()

	// Launch claude inside a real tmux session so the Agent tool is
	// available and teammate mode "auto" reliably resolves to "tmux"
	// (spawning teammates via CLAUDE_CODE_TEAMMATE_COMMAND).
	//
	// A PTY alone isn't sufficient — Claude Code checks for a real tmux
	// session, not just a TTY.
	sessionName := fmt.Sprintf("sea-smoke-%d", os.Getpid())

	// Write the prompt to a file, then a launcher script that reads it.
	// Using %q would escape newlines as literal \n in the shell.
	promptPath := filepath.Join(cfg.TmpDir, "smoke-prompt.txt")
	if err := os.WriteFile(promptPath, []byte(smokePrompt), 0644); err != nil {
		return fmt.Errorf("writing smoke prompt: %w", err)
	}

	launcherPath := filepath.Join(cfg.TmpDir, "launch-claude.sh")
	logFile := filepath.Join(cfg.TmpDir, "launcher.log")
	launcherContent := fmt.Sprintf(
		"#!/bin/sh\nexport CLAUDE_CODE_TEAMMATE_COMMAND=%q\ncd %q\necho \"CLAUDE_CODE_TEAMMATE_COMMAND=$CLAUDE_CODE_TEAMMATE_COMMAND\" > %q\necho \"PATH=$PATH\" >> %q\necho \"TMUX=$TMUX\" >> %q\nls -la \"$CLAUDE_CODE_TEAMMATE_COMMAND\" >> %q 2>&1\nexec %q --dangerously-skip-permissions \"$(cat %q)\"\n",
		cfg.WrapperBin, cfg.TmpDir, logFile, logFile, logFile, logFile, cfg.ClaudeBin, promptPath,
	)
	if err := os.WriteFile(launcherPath, []byte(launcherContent), 0755); err != nil {
		return fmt.Errorf("writing launcher script: %w", err)
	}

	// Create a detached tmux session running the launcher
	tmuxCmd := exec.Command("tmux", "new-session", "-d", "-s", sessionName,
		"-x", "200", "-y", "50",
		launcherPath,
	)
	if out, err := tmuxCmd.CombinedOutput(); err != nil {
		return fmt.Errorf("creating tmux session: %s: %w", out, err)
	}
	defer func() {
		exec.Command("tmux", "kill-session", "-t", sessionName).Run()
	}()

	fmt.Printf("Launched Claude Code in tmux session %q, waiting for smoke test results...\n", sessionName)
	fmt.Println()

	// Auto-dismiss interactive dialogs (trust dialog, etc.) by sending
	// Enter keys to the tmux session. The trust dialog has "Yes, I trust
	// this folder" pre-selected, so Enter confirms it.
	go func() {
		for i := 0; i < 10; i++ {
			time.Sleep(2 * time.Second)
			exec.Command("tmux", "send-keys", "-t", sessionName, "Enter").Run()
		}
	}()

	// Poll for the results file.
	resultsFile := filepath.Join(cfg.TmpDir, "smoke-results.txt")
	timer := time.NewTimer(timeout)
	defer timer.Stop()
	ticker := time.NewTicker(5 * time.Second)
	defer ticker.Stop()

	gotResults := false
	for !gotResults {
		select {
		case <-ticker.C:
			// Check if tmux session is still alive
			if err := exec.Command("tmux", "has-session", "-t", sessionName).Run(); err != nil {
				// Session died — check for results one last time
				if data, err := os.ReadFile(resultsFile); err == nil && len(data) > 0 {
					gotResults = true
					fmt.Println(string(data))
				}
				goto done
			}
			if data, err := os.ReadFile(resultsFile); err == nil && len(data) > 0 {
				gotResults = true
				fmt.Println(string(data))
			} else {
				fmt.Fprintf(os.Stderr, "[sea] Polling for %s...\n", resultsFile)
				// Capture tmux pane content for diagnostics
				if out, err := exec.Command("tmux", "capture-pane", "-t", sessionName, "-p").Output(); err == nil {
					// Only print non-empty, interesting lines
					lines := strings.Split(strings.TrimSpace(string(out)), "\n")
					for _, line := range lines {
						line = strings.TrimSpace(line)
						if line != "" && line != "❯" {
							fmt.Fprintf(os.Stderr, "  [tmux] %s\n", line)
						}
					}
				}
			}
		case <-timer.C:
			fmt.Fprintf(os.Stderr, "\n[sea] Timeout after %s — killing tmux session\n", timeout)
			goto done
		}
	}

done:
	// Kill the tmux session (defer will also try, but be explicit)
	exec.Command("tmux", "kill-session", "-t", sessionName).Run()

	fmt.Println()
	if gotResults {
		fmt.Println("Smoke test completed.")
	} else {
		fmt.Println("Smoke test did not produce smoke-results.txt.")
	}
	fmt.Printf("Inspect workspace: %s\n", cfg.TmpDir)

	// Print diagnostic logs
	for _, lf := range []struct{ name, path string }{
		{"Launcher Log", filepath.Join(cfg.TmpDir, "launcher.log")},
		{"Wrapper Log", filepath.Join(cfg.TmpDir, "wrapper.log")},
	} {
		if data, err := os.ReadFile(lf.path); err == nil {
			fmt.Printf("\n── %s ──\n", lf.name)
			fmt.Print(string(data))
		} else {
			fmt.Printf("\n%s not found\n", lf.name)
		}
	}

	return nil
}

// stripANSI removes ANSI escape sequences from a string.
func stripANSI(s string) string {
	var out strings.Builder
	i := 0
	for i < len(s) {
		if s[i] == '\x1b' {
			// Skip ESC [ ... (letter)
			i++
			if i < len(s) && s[i] == '[' {
				i++
				for i < len(s) && !((s[i] >= 'A' && s[i] <= 'Z') || (s[i] >= 'a' && s[i] <= 'z')) {
					i++
				}
				if i < len(s) {
					i++ // skip the final letter
				}
			}
		} else {
			out.WriteByte(s[i])
			i++
		}
	}
	return out.String()
}

