package flags

import (
	"fmt"
	"strings"
)

// ParseResult holds the extracted flags and the full original argument list.
type ParseResult struct {
	AgentName string   // value of --agent-name
	TeamName  string   // value of --team-name
	AllArgs   []string // original args, preserved verbatim
}

// Parse scans args for --agent-name and --team-name, extracting their values.
// All args are preserved verbatim in AllArgs for passthrough to the real claude binary.
// Unknown flags are ignored (forward-compatible). Returns an error if either
// --agent-name or --team-name is missing.
func Parse(args []string) (ParseResult, error) {
	result := ParseResult{AllArgs: args}

	for i := 0; i < len(args); i++ {
		arg := args[i]

		if _, val, ok := extractFlag(arg, "--agent-name"); ok {
			if val == "\x00" {
				return result, fmt.Errorf("--agent-name= requires a value")
			}
			if val != "" {
				result.AgentName = val
			} else if i+1 < len(args) {
				i++
				result.AgentName = args[i]
			}
			continue
		}

		if _, val, ok := extractFlag(arg, "--team-name"); ok {
			if val == "\x00" {
				return result, fmt.Errorf("--team-name= requires a value")
			}
			if val != "" {
				result.TeamName = val
			} else if i+1 < len(args) {
				i++
				result.TeamName = args[i]
			}
			continue
		}
	}

	if result.AgentName == "" {
		return result, fmt.Errorf("missing required flag --agent-name")
	}
	if result.TeamName == "" {
		return result, fmt.Errorf("missing required flag --team-name")
	}
	if err := ValidateAgentName(result.AgentName); err != nil {
		return result, fmt.Errorf("invalid --agent-name: %w", err)
	}

	return result, nil
}

// extractFlag checks if arg matches the given flag name.
// Returns (flagName, value, matched). Handles both "--flag value" and "--flag=value" forms.
// For "--flag=" (equals with empty RHS), returns the flag name with an explicit empty
// value marker so the caller can distinguish it from the "--flag" (space-separated) form.
func extractFlag(arg, flag string) (string, string, bool) {
	if arg == flag {
		return flag, "", true
	}
	if strings.HasPrefix(arg, flag+"=") {
		val := arg[len(flag)+1:]
		if val == "" {
			// --flag= with no value after equals is an explicit empty value.
			// Return a sentinel so Parse treats this as an error rather than
			// consuming the next arg.
			return flag, "\x00", true
		}
		return flag, val, true
	}
	return "", "", false
}

// ValidateAgentName rejects agent names that contain path traversal components
// or other dangerous patterns.
func ValidateAgentName(name string) error {
	if name == "" {
		return fmt.Errorf("agent name must not be empty")
	}
	if strings.Contains(name, "..") {
		return fmt.Errorf("agent name must not contain '..': %q", name)
	}
	if strings.ContainsAny(name, "/\\") {
		return fmt.Errorf("agent name must not contain path separators: %q", name)
	}
	if strings.HasPrefix(name, ".") {
		return fmt.Errorf("agent name must not start with '.': %q", name)
	}
	return nil
}

